import React, { useState, useEffect } from 'react';
import '../styles/PhoneIntel.css';
import CountryCodePicker, { COUNTRY_CODES } from './CountryCodePicker';
import { api } from '../utils/api';
import { THEMES } from '../themes';

/**
 * Phone Intel Tab Component
 * 
 * Features:
 * - Phone number input with optional country code
 * - Auto-detection of country code if missing
 * - Light/Deep scan toggle with progress indicator
 * - Display of phone intelligence (carrier, timezone, risk score)
 * - Display of linked emails and social accounts in tables
 * - Compatible with Flask JSON output
 */
const PhoneIntel = ({ theme }) => {
  const t = THEMES[theme || 'dark'];
  const [phoneNumber, setPhoneNumber] = useState('');
  const [selectedDialCode, setSelectedDialCode] = useState('+233'); // Default to Ghana
  const [isLoading, setIsLoading] = useState(false);
  const [scanType, setScanType] = useState('light'); // 'light' or 'deep'
  const [lookupResult, setLookupResult] = useState(null);
  const [error, setError] = useState(null);
  const [autoDetectedCountry, setAutoDetectedCountry] = useState(null);
  const [progress, setProgress] = useState(0);

  /**
   * Handle phone number input change
   */
  const handlePhoneChange = (e) => {
    const value = e.target.value;
    setPhoneNumber(value);

    // Auto-detect country if missing country code
    if (!value.startsWith('+') && value.length > 0) {
      detectCountry(value);
    }
  };

  /**
   * Detect country from phone number
   */
  const detectCountry = async (phone) => {
    try {
      // Use api.js which we know works
      const response = await api.phoneLookup(phone.replace(/\D/g, ''));

      if (response.data?.country_name) {
        setAutoDetectedCountry({
          country_name: response.data.country_name,
          flag: response.data.flag || '📍'
        });
      }
    } catch (err) {
      // Silent fail for auto-detection
      console.log('Country detection not available');
    }
  };

  /**
   * Perform phone lookup
   */
  const handleLookup = async () => {
    if (!phoneNumber.trim()) {
      setError('Please enter a phone number');
      return;
    }

    setIsLoading(true);
    setError(null);
    setLookupResult(null);
    setProgress(0);

    try {
      // Simulate progress for UX
      const progressInterval = setInterval(() => {
        setProgress((prev) => (prev < 90 ? prev + 10 : prev));
      }, 200);

      // Build full phone number if it doesn't start with +
      let fullPhone = phoneNumber.trim();
      if (!fullPhone.startsWith('+')) {
        const local = fullPhone.replace(/^0+/, '');
        fullPhone = `${selectedDialCode}${local}`;
      }

      const response = await api.phoneLookup(fullPhone);

      clearInterval(progressInterval);
      setProgress(100);

      if (response.status === 'success') {
        setLookupResult(response.data);
      } else {
        setError(response.message || 'Lookup failed');
      }
    } catch (err) {
      setError(err.message || 'Error performing lookup');
      setProgress(0);
    } finally {
      setIsLoading(false);
      setTimeout(() => setProgress(0), 500);
    }
  };

  /**
   * Handle batch lookup
   */
  const handleBatchLookup = async (phones) => {
    setIsLoading(true);
    setError(null);

    try {
      const response = await apiClient.post('/phone/batch', {
        phones
      });

      if (response.data?.status === 'success') {
        setLookupResult({
          ...response.data.data,
          is_batch: true,
          summary: response.data.summary
        });
      }
    } catch (err) {
      setError(err.response?.data?.message || 'Batch lookup failed');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="phone-intel-container">
      {/* Header */}
      <div className="intel-header">
        <h2>📱 Phone Intelligence</h2>
        <p>Ghost.py-style phone lookup: carrier, timezone, risk scoring, and linked accounts</p>
      </div>

      {/* Input Section */}
      <div className="intel-input-section">
        <div className="input-group">
          <label>Phone Number</label>
          <div className="phone-input-wrapper">
            <input
              type="tel"
              placeholder="Enter phone number (e.g., +1234567890 or 2025551234)"
              value={phoneNumber}
              onChange={handlePhoneChange}
              disabled={isLoading}
              className="phone-input"
            />
            {autoDetectedCountry && !selectedCountry && (
              <div className="auto-detect-badge">
                Auto-detected: {autoDetectedCountry.flag} {autoDetectedCountry.country_name}
              </div>
            )}
          </div>
        </div>

        <div className="input-group">
          <label>Country Code (Optional)</label>
          <CountryCodePicker
            value={selectedDialCode}
            onChange={setSelectedDialCode}
            disabled={isLoading}
            theme={theme}
          />
        </div>

        <div className="scan-toggle">
          <label>Scan Type</label>
          <div className="toggle-buttons">
            <button
              className={`toggle-btn ${scanType === 'light' ? 'active' : ''}`}
              onClick={() => setScanType('light')}
              disabled={isLoading}
            >
              ⚡ Light Scan (Fast)
            </button>
            <button
              className={`toggle-btn ${scanType === 'deep' ? 'active' : ''}`}
              onClick={() => setScanType('deep')}
              disabled={isLoading}
            >
              🔍 Deep Scan (Full)
            </button>
          </div>
        </div>

        <button
          className="lookup-btn"
          onClick={handleLookup}
          disabled={isLoading || !phoneNumber.trim()}
        >
          {isLoading ? '🔄 Looking up...' : '🔎 Lookup Phone'}
        </button>

        {/* Progress Indicator */}
        {progress > 0 && progress < 100 && (
          <div className="progress-container">
            <div className="progress-bar" style={{ width: `${progress}%` }} />
            <span className="progress-text">{progress}%</span>
          </div>
        )}
      </div>

      {/* Error Message */}
      {error && (
        <div className="error-banner">
          ⚠️ {error}
          <button onClick={() => setError(null)} className="close-btn">×</button>
        </div>
      )}

      {/* Results Section */}
      {lookupResult && (
        <div className="intel-results">
          {/* Basic Info Card */}
          <div className="result-card phone-details">
            <h3>📱 Basic Info</h3>
            <div className="detail-grid">
              <div className="detail-item">
                <span className="detail-label">Full Number:</span>
                <span className="detail-value">{lookupResult.number || phoneNumber}</span>
              </div>
              <div className="detail-item">
                <span className="detail-label">Detected Country:</span>
                <span className="detail-value">{lookupResult.country || '—'}</span>
              </div>
              <div className="detail-item">
                <span className="detail-label">Carrier:</span>
                <span className="detail-value">{lookupResult.carrier || '—'}</span>
              </div>
              <div className="detail-item">
                <span className="detail-label">Timezone:</span>
                <span className="detail-value">{lookupResult.timezone || '—'}</span>
              </div>
              <div className="detail-item">
                <span className="detail-label">Risk Score:</span>
                <span className="detail-value" style={getRiskScoreStyle(lookupResult.risk_score || 0)}>
                  {lookupResult.risk_score !== undefined ? `${Math.round(lookupResult.risk_score * 100)}/100` : '—'}
                </span>
              </div>
            </div>
          </div>

          {/* Linked Emails Card */}
          <div className="result-card">
            <h3>📧 Linked Emails</h3>
            {lookupResult.emails_found && lookupResult.emails_found.length > 0 ? (
              <table className="result-table">
                <thead>
                  <tr>
                    <th>Email Address</th>
                    <th>Status</th>
                  </tr>
                </thead>
                <tbody>
                  {lookupResult.emails_found.map((email, idx) => (
                    <tr key={idx}>
                      <td className="email-cell">{email}</td>
                      <td><span className="Badge potential">Potential</span></td>
                    </tr>
                  ))}
                </tbody>
              </table>
            ) : (
              <div className="no-results">No emails found</div>
            )}
          </div>

          {/* Linked Social Accounts Card */}
          <div className="result-card">
            <h3>👥 Linked Social Accounts</h3>
            {lookupResult.social_accounts && Object.keys(lookupResult.social_accounts).length > 0 ? (
              <table className="result-table">
                <thead>
                  <tr>
                    <th>Platform</th>
                    <th>Handle</th>
                    <th>Status</th>
                  </tr>
                </thead>
                <tbody>
                  {Object.entries(lookupResult.social_accounts).map(([platform, handle], idx) => (
                    <tr key={idx}>
                      <td className="platform-cell">
                        <strong>{formatPlatformName(platform)}</strong>
                      </td>
                      <td>{handle}</td>
                      <td><span className="Badge potential">Potential</span></td>
                    </tr>
                  ))}
                </tbody>
              </table>
            ) : (
              <div className="no-results">No social accounts found</div>
            )}
          </div>
        </div>
      )}

      {/* Empty State */}
      {!lookupResult && !isLoading && (
        <div className="empty-state">
          <div className="empty-icon">📱</div>
          <p>Enter a phone number to start the lookup</p>
          <small>Supports international formats with or without country codes</small>
        </div>
      )}
    </div>
  );
};

/**
 * Get color and styling for risk score
 */
function getRiskScoreStyle(score) {
  let color = '#4CAF50'; // Green
  if (score >= 0.8) color = '#F44336'; // Red
  else if (score >= 0.6) color = '#FF9800'; // Orange
  else if (score >= 0.4) color = '#FFC107'; // Yellow

  return {
    borderColor: color,
    color: color
  };
}

/**
 * Get human-readable risk level
 */
function getRiskLevel(score) {
  if (score >= 0.8) return '🔴 CRITICAL';
  if (score >= 0.6) return '🟠 HIGH';
  if (score >= 0.4) return '🟡 MEDIUM';
  if (score >= 0.2) return '🟢 LOW';
  return '✅ MINIMAL';
}

/**
 * Format platform name for display
 */
function formatPlatformName(platform) {
  return platform
    .split('_')
    .map((word) => word.charAt(0).toUpperCase() + word.slice(1))
    .join(' ');
}

export default PhoneIntel;
